import React, { useEffect, useState } from 'react';
import axios from 'axios';
import TaskList from './TaskList';
import { useNavigate } from 'react-router-dom';
import MenuBar from './MenuBar';
import Swal from 'sweetalert2';

const Dashboard = () => {
  const [tasks, setTasks] = useState([]);
  const [userRole, setUserRole] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const fetchUserRole = async () => {
      try {
        const token = localStorage.getItem('token');
        const cleanedToken = token?.replace(/^Bearer\s+/i, ''); // Ensure no duplicate "Bearer"

        // Fetch user profile to get the role
        const response = await axios.get('http://localhost:3000/api/auth/profile', {
          headers: {
            Authorization: `Bearer ${cleanedToken}`,
          },
        });

        setUserRole(response.data.role);
      } catch (error) {
        console.error('Error fetching user role:', error);
      }
    };

    const fetchTasks = async () => {
      try {
        const token = localStorage.getItem('token');
        const cleanedToken = token?.replace(/^Bearer\s+/i, '');

        const response = await axios.get('http://localhost:3000/api/tasks', {
          headers: {
            Authorization: `Bearer ${cleanedToken}`,
          },
        });

        setTasks(response.data);
      } catch (error) {
        if (error.response && error.response.status === 401) {
          navigate('/');
        }
      }
    };

    fetchUserRole(); // Fetch role first
    fetchTasks(); // Fetch tasks
  }, [navigate]);

  const handleRequestRoleChange = async () => {
    try {
      const token = localStorage.getItem('token');
      const cleanedToken = token?.replace(/^Bearer\s+/i, '');

      // Send role change request
      await axios.post(
        'http://localhost:3000/api/users/request-role-change',
        {},
        {
          headers: {
            Authorization: `Bearer ${cleanedToken}`,
          },
        }
      );

      // Show success confirmation
      Swal.fire({
        icon: 'success',
        title: 'Request Submitted!',
        text: 'Your request for role change has been sent to the admin.',
      });
    } catch (error) {
      console.error('Error requesting role change:', error);
      Swal.fire({
        icon: 'error',
        title: 'Error',
        text: 'Could not send request. Please try again later.',
      });
    }
  };

  return (
    <div>
      <MenuBar />
      <h2>Dashboard</h2>

      {userRole === 'intern' && (
        <button className="role-request-button" onClick={handleRequestRoleChange}>
          Request Role Change
        </button>
      )}

      {tasks.length === 0 ? (
        <div>
          <p>No tasks available. Please create a new task.</p>
          <button onClick={() => navigate('/add-task')}>Create New Task</button>
        </div>
      ) : (
        <TaskList tasks={tasks} />
      )}
    </div>
  );
};

export default Dashboard;
